// n8n Code node (2.8+)

// First input item
const { json } = $input.first();

// Prefer direct fields if present
let apiKey = json.api_key ?? json.apiKey ?? null;
const workerId =
  json.worker_id ??
  json.workerId ??
  $('Execute Workflow Trigger')?.first()?.json?.args?.worker_id ??
  null;

// Fallback: register_worker can be an object or string
if (!apiKey) {
  const raw = json.register_worker ?? json.registerWorker ?? null;

  if (typeof raw === 'string') {
    const m = raw.match(/API Key:\s*(sk_[a-zA-Z0-9]+)/);
    apiKey = m?.[1] ?? null;
  } else if (raw && typeof raw === 'object') {
    apiKey = raw.api_key ?? raw.apiKey ?? null;
  }
}

return [
  {
    json: {
      worker_id: workerId,
      api_key: apiKey,
    },
  },
];
